export function detectMarkdown(t){if(!t||"string"!=typeof t)return!1;const r=t.replace(/<[^>]*>/g,"").trim(),s=[/^#{1,6}\s+.+$/m,/^```[\s\S]*?```$/m,/^\|.+\|.+\|.*$/m,/^>\s+.+$/m,/^\s*\*{3,}\s*$/m,/^\s*-{3,}\s*$/m,/^\s*_{3,}\s*$/m];for(const t of s)if(t.test(r))return!0;const n=[/^\s*[-*+]\s+.+$/m,/^\s*\d+\.\s+.+$/m,/\*\*[^*]+\*\*/,/(?<!\*)\*[^*]+\*(?!\*)/,/\[.+?\]\(.+?\)/,/!\[.*?\]\(.+?\)/,/`[^`\n]+`/,/^\s{4,}.+$/m];let o=0;for(const t of n)t.test(r)&&o++;return o>=2}export async function markdownToHTML(t){try{const r=await import("./marked.js"),{marked:s}=r;return s.parse(t)}catch(r){return console.warn("Failed to parse markdown, falling back to original text:",r),t}}